#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, R;
        scanf("%d %d", &N, &R);
        double xi[N], yi[N], zi[N];
        for (int i = 0; i < N; i++) {
            scanf("%lf %lf %lf", &xi[i], &yi[i], &zi[i]);
        }
        int min_asteroids = N;
        for (double theta = 0; theta <= 2 * M_PI; theta += 0.01) {
            for (double phi = 0; phi <= M_PI; phi += 0.01) {
                int observed = 0;
                for (int i = 0; i < N; i++) {
                    double angle = acos((xi[i] * sin(phi) * cos(theta) + yi[i] * sin(phi) * sin(theta) + zi[i] * cos(phi)) / sqrt(xi[i] * xi[i] + yi[i] * yi[i] + zi[i] * zi[i]));
                    if (angle >= 1e-3) {
                        observed++;
                    }
                }
                min_asteroids = (observed < min_asteroids) ? observed : min_asteroids;
            }
        }
        printf("%d\n", min_asteroids);
    }
    return 0;
}

