import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int R = scanner.nextInt();
            double[] xi = new double[N];
            double[] yi = new double[N];
            double[] zi = new double[N];
            for (int i = 0; i < N; i++) {
                xi[i] = scanner.nextDouble();
                yi[i] = scanner.nextDouble();
                zi[i] = scanner.nextDouble();
            }
            int min_asteroids = N;
            for (double theta = 0; theta <= 2 * Math.PI; theta += 0.01) {
                for (double phi = 0; phi <= Math.PI; phi += 0.01) {
                    int observed = 0;
                    for (int i = 0; i < N; i++) {
                        double angle = Math.acos((xi[i] * Math.sin(phi) * Math.cos(theta) + yi[i] * Math.sin(phi) * Math.sin(theta) + zi[i] * Math.cos(phi)) / Math.sqrt(xi[i] * xi[i] + yi[i] * yi[i] + zi[i] * zi[i]));
                        if (angle >= 1e-3) {
                            observed++;
                        }
                    }
                    min_asteroids = (observed < min_asteroids) ? observed : min_asteroids;
                }
            }
            System.out.println(min_asteroids);
        }
    }
}

code.JavaScript:
const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, R] = readline().split(' ').map(Number);
    const xi = [], yi = [], zi = [];
    for (let j = 0; j < N; j++) {
        const [x, y, z] = readline().split(' ').map(Number);
        xi.push(x);
        yi.push(y);
        zi.push(z);
    }
    let min_asteroids = N;
    for (let theta = 0; theta <= 2 * Math.PI; theta += 0.01) {
        for (let phi = 0; phi <= Math.PI; phi += 0.01) {
            let observed = 0;
            for (let j = 0; j < N; j++) {
                const angle = Math.acos((xi[j] * Math.sin(phi) * Math.cos(theta) + yi[j] * Math.sin(phi) * Math.sin(theta) + zi[j] * Math.cos(phi)) / Math.sqrt(xi[j] ** 2 + yi[j] ** 2 + zi[j] ** 2));
                if (angle >= 1e-3) {
                    observed++;
                }
            }
            min_asteroids = Math.min(min_asteroids, observed);
        }
    }
    console.log(min_asteroids);
}

